function TodoList() {
  const [items, setItems] = React.useState([
    {id:1,text:'REPLACE_WITH_TASK_1',done:false,priority:'medium'},
    {id:2,text:'REPLACE_WITH_TASK_2',done:false,priority:'high'}
  ]);
  const [input, setInput] = React.useState('');
  const [prio, setPrio] = React.useState('medium');

  const add = () => {
    if (!input.trim()) return;
    setItems([...items,{id:Date.now(),text:input,done:false,priority:prio}]);
    setInput('');
  };

  const toggle = (id) => setItems(items.map(i=>i.id===id?{...i,done:!i.done}:i));
  const remove = (id) => setItems(items.filter(i=>i.id!==id));

  const pColor = {high:'#FF3B30',medium:'#FF9500',low:'#34C759'};

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Todo List</div>
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&add()}
          style={{flex:1,padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}
          placeholder="Add a task…"/>
        <select value={prio} onChange={e=>setPrio(e.target.value)}
          style={{padding:'8px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}>
          <option value="high">High</option>
          <option value="medium">Med</option>
          <option value="low">Low</option>
        </select>
        <button onClick={add}
          style={{padding:'8px 16px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer'}}>
          Add
        </button>
      </div>
      <div style={{flex:1,overflow:'auto'}}>
        {items.sort((a,b)=>(a.done?1:0)-(b.done?1:0)).map(item=> (
          <div key={item.id} style={{display:'flex',alignItems:'center',gap:8,padding:'8px 0',borderBottom:'1px solid #eee'}}>
            <input type="checkbox" checked={item.done} onChange={()=>toggle(item.id)}
              style={{width:18,height:18,cursor:'pointer'}}/>
            <span style={{flex:1,textDecoration:item.done?'line-through':'none',color:item.done?'#888':'#000',fontSize:14}}>
              {item.text}
            </span>
            <span style={{width:8,height:8,borderRadius:'50%',background:pColor[item.priority]}}/>
            <button onClick={()=>remove(item.id)}
              style={{background:'none',border:'none',color:'#FF3B30',cursor:'pointer',fontSize:16}}>
              ×
            </button>
          </div>
        ))}
      </div>
      <div style={{fontSize:12,color:'#888',marginTop:8}}>
        {items.filter(i=>!i.done).length} of {items.length} remaining
      </div>
    </div>
  );
}
render(<TodoList/>);
